{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@300;500;700&family=Amatic+SC:wght@400;700&display=swap');

:root {
  --tv-black: 10, 0, 0;
  --tv-screen: 255, 40, 40;
  --tv-blue: 200, 0, 0;
  --tv-white: 255, 230, 230;
  --tv-pink: 255, 80, 80;
  --tv-shadow: 0, 0, 0;
  --body-font: 'Rubik', sans-serif;
  --retro-font: 'Amatic SC', cursive;
  --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
  border: 3px solid rgb(var(--tv-blue));
  margin: 12px auto;
  border-radius: 20px;
  box-shadow: 0 0 20px rgba(var(--tv-screen), 0.6), inset 0 0 10px rgba(var(--tv-blue), 0.4);
  background: linear-gradient(
    135deg,
    rgb(var(--tv-black)),
    rgba(var(--tv-blue), 0.15),
    rgba(var(--tv-screen), 0.05)
  );
  background-image:
    repeating-linear-gradient(0deg, rgba(var(--tv-white), 0.05) 0px, transparent 2px, transparent 4px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgb(var(--tv-black));
  --theme-page-background-color--secondary: rgba(var(--tv-blue), 0.1);
  --theme-link-color: rgb(255, 255, 255);
  --theme-border-color: rgb(var(--tv-pink));
  --theme-community-header-color: rgb(var(--tv-blue));
  --theme-sticky-nav-background-color: rgba(var(--tv-black), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--tv-screen));
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-pink));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(var(--tv-white), 0.9);
  --theme-page-background-color--secondary: rgb(var(--tv-black));
  --theme-link-color: rgb(255, 255, 255);
  --theme-border-color: rgb(var(--tv-pink));
  --theme-community-header-color: rgb(var(--tv-screen));
  --theme-sticky-nav-background-color: rgba(var(--tv-white), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--tv-black));
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-blue));
}

a,
a:visited {
  color: rgb(255, 255, 255) !important;
  text-decoration: none;
  transition: color 0.3s ease, text-shadow 0.3s ease;
}

a:hover,
a:focus {
  color: rgb(var(--tv-screen)) !important;
  text-shadow: 0 0 6px rgba(var(--tv-screen), 0.9),
               0 0 12px rgba(var(--tv-blue), 0.7);
}

.page-side-tools .page-side-tool {
  border: 2px solid rgb(var(--tv-screen));
  box-shadow: 0 0 12px rgba(var(--tv-screen), 0.6);
  border-radius: 50%;
  background-color: rgba(var(--tv-black), 0.9);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.page-side-tool:hover {
  transform: scale(1.1) rotate(3deg);
  box-shadow: 0 0 20px rgba(var(--tv-blue), 0.9);
}

.titleblock,
.dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--tv-screen), 0.2), rgba(var(--tv-black), 0.95));
  border: 3px solid rgb(var(--tv-pink));
  border-radius: 25px;
  padding: 1rem;
  font-family: var(--retro-font);
  font-weight: 700;
  color: rgb(var(--tv-screen));
  text-shadow: 0 0 5px rgba(var(--tv-screen), 0.9), 0 0 15px rgba(var(--tv-blue), 0.7);
  font-size: 2.3em;
  letter-spacing: 2px;
  transform: rotate(-1deg);
  animation: neon-flicker 2s infinite alternate;
}

.progress {
  background: rgba(var(--tv-black), 0.95);
  border: 2px solid rgb(var(--tv-blue));
  border-radius: 15px;
  color: rgb(var(--tv-white));
  box-shadow: 0 0 10px rgba(var(--tv-screen), 0.6);
}

.progress .bar {
  background: linear-gradient(to right, rgb(var(--tv-blue)), rgb(var(--tv-screen)));
  border-radius: 12px;
  box-shadow: 0 0 15px rgba(var(--tv-screen), 0.8);
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--retro-font);
  color: rgb(var(--tv-screen));
  text-transform: uppercase;
  letter-spacing: 4px;
  text-shadow: 0 0 6px rgba(var(--tv-screen), 0.9), 0 0 15px rgba(var(--tv-blue), 0.8);
  font-size: calc(1.5rem + 0.6vw);
}

h1 {
  font-size: calc(2rem + 1.2vw);
}

@keyframes neon-flicker {
  0%, 19%, 21%, 60%, 62%, 100% {
    opacity: 1;
    text-shadow: 0 0 6px rgba(var(--tv-screen), 1), 0 0 20px rgba(var(--tv-blue), 0.9);
  }
  20%, 61% {
    opacity: 0.7;
    text-shadow: none;
  }
}
}}

